<script type="application/ld+json">
{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "What exactly do I get?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "A 40+ page PDF natal chart report covering 12 life areas — personality traits, love patterns, career strengths, and more. Includes your natal wheel chart. Delivered directly to your email."
      }
    },
    {
      "@type": "Question",
      "name": "How are the reports created?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Your birth data goes through a multi-stage analysis pipeline. First, Astrolog 7.80 (Swiss Ephemeris) computes exact positions for 20 celestial bodies and maps 50+ aspect configurations with precise orbs. We then extract your chart's unique statistical signature — planetary weights, elemental distribution, aspect geometry, and dispositorship chains. Each of the 13 report sections is then written individually for your placements, using the interpretive frameworks of Liz Greene (psychological astrology), Robert Hand (systematic aspect analysis), and Steven Forrest (evolutionary astrology). Every report is individually composed and quality-checked before delivery."
      }
    },
    {
      "@type": "Question",
      "name": "What makes ZodiacID different?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Every report is individually written and quality-checked. 20 celestial bodies, 50+ aspects with exact orbs, dispositorship chains, and house ruler cross-references. 40+ pages of original birth chart interpretation — no templates, no recycled paragraphs. Available natively in 3 languages."
      }
    },
    {
      "@type": "Question",
      "name": "Are these reports scientifically proven?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. Astrology is not a science. We don't predict the future — we offer a framework for self-exploration based on your birth chart."
      }
    },
    {
      "@type": "Question",
      "name": "What if I don't know my exact birth time?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Check your birth certificate or ask a family member. An approximate time usually works, though exact time gives the most detailed results."
      }
    },
    {
      "@type": "Question",
      "name": "How long until I receive my report?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Within 24 hours. Every report is individually composed and quality-checked before delivery."
      }
    },
    {
      "@type": "Question",
      "name": "Can I get a refund?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. Full refund within 14 days, no questions asked."
      }
    },
    {
      "@type": "Question",
      "name": "What languages are available?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "English, Russian, and Estonian — written natively, not translated."
      }

