  "@context": "https://schema.org",
  "@type": "FAQPage",
  "inLanguage": "en",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "What's a Red Flag Check?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "A focused analysis of the hardest aspects between two birth charts. Instead of covering every relationship theme, we zoom in on friction: the top reasons you'll argue, realistic conflict scenarios based on your chart dynamics, and practical scripts for navigating those moments. Short, direct, and honest."
      }
    },
    {
      "@type": "Question",
      "name": "How is this different from the Relationship X-Ray?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "The Relationship X-Ray is a comprehensive synastry report covering chemistry, communication, growth, and conflict across all aspects. The Red Flag Check is narrower and cheaper — it focuses only on friction points and conflict patterns. Think of it as the \"what will we fight about\" report. If you want the full picture, get the Relationship X-Ray. If you want a quick, honest look at the hard parts, this is it."
      }
    },
    {
      "@type": "Question",
      "name": "Is it really that honest?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. The Red Flag Check doesn't soften the hard aspects or add disclaimers to every observation. If your charts show a tendency toward power struggles, we name it. If there's a pattern suggesting emotional manipulation, we describe how it tends to play out. The survival scripts are there to help — but the analysis itself doesn't sugar-coat anything."
      }
    }
  ]
}
</script>

