/* ==========================================================
   ZodiacID — Production Stylesheet
   Dark cosmic theme: navy #0f0e17, gold #d4a853
   Fonts: Bebas Neue (display) + DM Sans (body)
   ========================================================== */

/* ========== CSS Custom Properties ========== */
:root {
  --bg-navy: #0f0e17;
  --bg-card: #1a1929;
  --bg-elevated: #232136;
  --gold: #d4a853;
  --gold-hover: #e0b96a;
  --text: #e0dfe4;
  --text-muted: #8b8a94;
  --white: #ffffff;
  --border: rgba(255, 255, 255, 0.08);
  --accent-red: #c0392b;
  --accent-purple: #7c3aed;
  --accent-green: #27ae60;

  --theme-red-primary: #c0392b;
  --theme-red-bg: #2d1a1a;
  --theme-parenting-primary: #7c3aed;
  --theme-parenting-bg: #1e1a2d;

  --font-display: 'Bebas Neue', sans-serif;
  --font-body: 'DM Sans', sans-serif;

  --container-max: 1120px;
  --section-padding: 4rem 0;

  --radius: 8px;
  --radius-lg: 12px;
  --radius-xl: 16px;
}

/* ========== Reset ========== */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-body);
  background: var(--bg-navy);
  color: var(--text);
  font-size: 17px;
  line-height: 1.75;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: var(--gold);
  text-decoration: none;
  transition: color 0.2s;
}

a:hover {
  color: var(--gold-hover);
}

ul, ol {
  list-style: none;
}

/* ========== Skip Link (Accessibility) ========== */
.skip-link {
  position: absolute;
  top: -100%;
  left: 0;
  background: var(--gold);
  color: var(--bg-navy);
  padding: 0.5rem 1rem;
  z-index: 1000;
  font-weight: 600;
  border-radius: 0 0 var(--radius) 0;
}

.skip-link:focus {
  top: 0;
}

/* ========== Layout ========== */
.container {
  max-width: var(--container-max);
  margin: 0 auto;
  padding: 0 1.5rem;
}

section {
  padding: var(--section-padding);
}

/* ========== Typography ========== */
h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-display);
  color: var(--white);
  line-height: 1.2;
  letter-spacing: 0.02em;
}

h1 { font-size: 3rem; }
h2 { font-size: 2rem; }
h3 { font-size: 1.5rem; }
h4 { font-size: 1.15rem; }

p {
  margin-bottom: 1rem;
  line-height: 1.7;
}

.section-title {
  font-family: var(--font-display);
  font-size: 2rem;
  color: var(--white);
  margin-bottom: 1.5rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.section-subtitle {
  color: var(--text-muted);
  font-size: 1.05rem;
  margin-bottom: 2rem;
  max-width: 640px;
}

/* ========== Buttons ========== */
.btn {
  display: inline-block;
  padding: 0.7rem 1.5rem;
  border-radius: var(--radius);
  font-family: var(--font-body);
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
  border: none;
  text-align: center;
  text-decoration: none;
}

.btn-gold {
  background: var(--gold);
  color: var(--bg-navy);
  font-weight: 700;
}

.btn-gold:hover {
  background: var(--gold-hover);
  color: var(--bg-navy);
  transform: translateY(-1px);
  box-shadow: 0 4px 15px rgba(212, 168, 83, 0.3);
}

.btn-gold:active {
  transform: translateY(0);
}

.btn-gold:disabled {
  opacity: 0.6;
  cursor: not-allowed;
  transform: none;
  box-shadow: none;
}

.btn-outline {
  background: transparent;
  color: var(--gold);
  border: 1px solid var(--gold);
}

.btn-outline:hover {
  background: rgba(212, 168, 83, 0.1);
  color: var(--gold-hover);
}

.btn-secondary {
  background: var(--bg-elevated);
  color: var(--text);
  border: 1px solid var(--border);
}

.btn-secondary:hover {
  background: var(--bg-card);
  border-color: var(--gold);
  color: var(--white);
}

.btn-lg {
  padding: 1rem 2rem;
  font-size: 1.1rem;
}

/* ========== Site Header ========== */
.site-header {
  position: sticky;
  top: 0;
  z-index: 200;
  background: rgba(15, 14, 23, 0.95);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--border);
  padding: 0.75rem 0;
}

.site-header .container {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.site-logo {
  font-family: var(--font-display);
  font-size: 1.6rem;
  color: var(--gold);
  letter-spacing: 0.04em;
  text-decoration: none;
}

.site-logo:hover {
  color: var(--gold-hover);
}

.nav-links {
  display: flex;
  gap: 1.5rem;
  align-items: center;
}

.nav-links a {
  color: var(--text-muted);
  font-size: 0.9rem;
  font-weight: 500;
  transition: color 0.2s;
}

.nav-links a:hover,
.nav-links a.active {
  color: var(--gold);
}

/* ========== Language Switcher ========== */
.lang-switcher {
  display: flex;
  gap: 0.75rem;
  align-items: center;
  font-size: 0.8rem;
  margin-left: 1rem;
}

.lang-switcher a {
  color: var(--text-muted);
  text-decoration: none;
  transition: color 0.2s;
}

.lang-switcher a:hover {
  color: var(--gold);
}

.lang-switcher .active {
  color: var(--gold);
  font-weight: 600;
}

.nav-toggle {
  display: none;
  background: none;
  border: none;
  color: var(--text);
  font-size: 1.5rem;
  cursor: pointer;
  padding: 0.25rem;
}

/* ========== Hero ========== */
.hero {
  position: relative;
  padding: 5rem 0 4rem;
  overflow: hidden;
  min-height: 520px;
  display: flex;
  align-items: center;
}

.hero .container {
  position: relative;
  z-index: 2;
}

.hero-title {
  font-size: 3.5rem;
  max-width: 640px;
  line-height: 1.1;
  margin-bottom: 1.25rem;
}

.hero-subline {
  font-size: 1.15rem;
  color: var(--text-muted);
  max-width: 560px;
  line-height: 1.7;
  margin-bottom: 2rem;
}

.hero-actions {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

/* ========== Product Hero (interior pages) ========== */
.product-hero {
  padding: 3rem 0 2rem;
  border-bottom: 1px solid var(--border);
}

.product-hero .hero-title {
  font-size: 2.8rem;
  margin-bottom: 0.5rem;
}

.product-hero .hero-subline {
  margin-bottom: 0;
}

/* ========== Trust Strip ========== */
.trust-strip {
  text-align: center;
  padding: 1.25rem 0;
  color: var(--text-muted);
  font-size: 0.85rem;
  letter-spacing: 0.02em;
  border-bottom: 1px solid var(--border);
  background: var(--bg-card);
}

.trust-strip .separator {
  margin: 0 0.75rem;
  color: var(--gold);
  opacity: 0.6;
}

/* ========== Card Grid ========== */
.card-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.25rem;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 1.75rem;
  display: flex;
  flex-direction: column;
  transition: border-color 0.2s, transform 0.2s;
}

.card:hover {
  border-color: rgba(212, 168, 83, 0.2);
  transform: translateY(-2px);
}

.card h3 {
  font-size: 1.3rem;
  margin-bottom: 0.5rem;
}

.card .price {
  color: var(--gold);
  font-size: 1.5rem;
  font-weight: 700;
  margin-bottom: 0.75rem;
}

.card p {
  color: var(--text-muted);
  font-size: 1rem;
  line-height: 1.7;
}

.card-actions {
  display: flex;
  gap: 0.75rem;
  margin-top: auto;
  padding-top: 1.25rem;
  flex-wrap: wrap;
}

.card .badge {
  display: inline-block;
  background: rgba(212, 168, 83, 0.15);
  color: var(--gold);
  padding: 0.2rem 0.6rem;
  border-radius: 3px;
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 0.75rem;
}

/* ========== Theme Variants ========== */
.theme-red .card {
  border-color: rgba(192, 57, 43, 0.2);
}
.theme-red .card:hover {
  border-color: rgba(192, 57, 43, 0.4);
}
.theme-red .section-title,
.theme-red .card h3 {
  color: var(--theme-red-primary);
}

.theme-parenting .card {
  border-color: rgba(124, 58, 237, 0.2);
}
.theme-parenting .card:hover {
  border-color: rgba(124, 58, 237, 0.4);
}
.theme-parenting .section-title,
.theme-parenting .card h3 {
  color: var(--theme-parenting-primary);
}

/* ========== Steps (How It Works) ========== */
.steps {
  counter-reset: steps;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1.5rem;
}

.steps li {
  counter-increment: steps;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1.5rem;
  position: relative;
}

.steps li::before {
  content: counter(steps);
  display: block;
  font-family: var(--font-display);
  font-size: 2rem;
  color: var(--gold);
  margin-bottom: 0.5rem;
  line-height: 1;
}

.steps li h4 {
  margin-bottom: 0.5rem;
}

.steps li p {
  color: var(--text-muted);
  font-size: 0.9rem;
}

/* ========== Testimonials ========== */
.testimonials {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 1.25rem;
}

.testimonial {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1.5rem;
}

.testimonial p {
  font-style: italic;
  color: var(--text);
  line-height: 1.7;
  margin-bottom: 0.75rem;
}

.testimonial cite {
  display: block;
  font-style: normal;
  font-size: 0.85rem;
  color: var(--gold);
}


/* ========== Sticky CTA Bar ========== */
.sticky-cta {
  position: sticky;
  bottom: 0;
  background: var(--bg-card);
  border-top: 1px solid var(--border);
  padding: 1rem 2rem;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  z-index: 100;
  box-shadow: 0 -4px 20px rgba(0, 0, 0, 0.3);
}

.sticky-cta .cta-text {
  color: var(--text);
  font-size: 1rem;
}

.sticky-cta .btn-gold {
  white-space: nowrap;
}

/* ========== Full Report Layout ========== */
.report-full {
  max-width: 720px;
  margin: 0 auto;
  padding: 2rem 1rem;
}

.report-full h2 {
  color: var(--gold);
  font-family: var(--font-display);
  font-size: 1.6rem;
  margin-top: 3rem;
  margin-bottom: 1rem;
  letter-spacing: 0.02em;
}

.report-full h3 {
  color: var(--white);
  font-size: 1.2rem;
  margin-top: 2rem;
  margin-bottom: 0.75rem;
}

.report-full p {
  line-height: 1.85;
  margin-bottom: 1rem;
  color: var(--text);
  font-size: 0.95rem;
}

.report-full ul,
.report-full ol {
  margin-bottom: 1rem;
  padding-left: 1.5rem;
}

.report-full li {
  list-style: disc;
  margin-bottom: 0.4rem;
  color: var(--text);
  font-size: 0.95rem;
  line-height: 1.7;
}

.report-full ol li {
  list-style: decimal;
}

/* ========== Trust Strip ========== */
.trust-bar {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 1.25rem 1.5rem;
  text-align: center;
  color: var(--text-muted);
  font-size: 0.9rem;
}

/* ========== Report Excerpt ========== */
.report-excerpt {
  background: var(--bg-card);
  border-left: 3px solid var(--gold);
  padding: 1.5rem 1.5rem 1.5rem 2rem;
  border-radius: 0 var(--radius) var(--radius) 0;
  margin: 1.5rem 0;
  color: var(--text);
  line-height: 1.85;
  font-size: 0.95rem;
}

.report-excerpt cite {
  display: block;
  margin-top: 1rem;
  font-style: normal;
  font-size: 0.9rem;
  color: var(--gold);
}

/* ========== Natal Wheel Image ========== */
.wheel-image {
  width: 100%;
  max-width: 420px;
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  box-shadow: 0 0 40px rgba(212, 168, 83, 0.08);
}

.wheel-image-hero {
  position: absolute;
  right: -5%;
  top: 50%;
  transform: translateY(-50%);
  opacity: 0.12;
  max-width: 500px;
  pointer-events: none;
}

.wheel-glow {
  filter: drop-shadow(0 0 20px rgba(212, 168, 83, 0.15));
}

/* ========== Feature Grid ========== */
.feature-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.25rem;
}

.feature-item {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1.25rem;
}

.feature-item h4 {
  color: var(--gold);
  font-size: 1rem;
  margin-bottom: 0.5rem;
}

.feature-item p {
  color: var(--text-muted);
  font-size: 0.9rem;
  line-height: 1.6;
}

/* ========== Comparison Table ========== */
.compare-table {
  width: 100%;
  border-collapse: collapse;
  margin: 1.5rem 0;
}

.compare-table th,
.compare-table td {
  padding: 0.75rem 1rem;
  text-align: left;
  border-bottom: 1px solid var(--border);
  font-size: 0.95rem;
}

.compare-table th {
  color: var(--text-muted);
  font-weight: 600;
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.compare-table td:first-child { color: var(--text); }
.compare-table .us { color: var(--gold); font-weight: 600; }
.compare-table .them { color: var(--text-muted); }

/* ========== Chart Badges ========== */
.chart-badges {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin: 1rem 0;
}

.chart-badge {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 0.4rem 0.85rem;
  font-size: 0.85rem;
}

.chart-badge strong {
  color: var(--gold);
  margin-right: 0.35rem;
}

/* ========== Order Form ========== */
.order-form {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 2rem;
  max-width: 560px;
  margin: 2rem auto;
}

.order-form h3 {
  text-align: center;
  margin-bottom: 0.5rem;
}

.order-form .form-price {
  text-align: center;
  font-size: 1.5rem;
  color: var(--gold);
  font-weight: 700;
  margin-bottom: 1.5rem;
}

.order-form .form-divider {
  border: none;
  border-top: 1px solid var(--border);
  margin: 1.5rem 0;
}

.order-form .form-section-label {
  color: var(--gold);
  font-weight: 600;
  font-size: 0.9rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  margin-bottom: 1rem;
}

.form-group {
  margin-bottom: 1rem;
}

.form-group label {
  display: block;
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-bottom: 0.35rem;
  font-weight: 500;
}

.form-group input,
.form-group select,
.form-group textarea {
  width: 100%;
  padding: 0.65rem 0.85rem;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  font-family: var(--font-body);
  font-size: 0.95rem;
  transition: border-color 0.2s;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
  outline: none;
  border-color: var(--gold);
  box-shadow: 0 0 0 2px rgba(212, 168, 83, 0.15);
}

.form-group input::placeholder {
  color: var(--text-muted);
  opacity: 0.6;
}

.form-group .field-note {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 0.25rem;
}

.form-group .field-error {
  font-size: 0.8rem;
  color: var(--accent-red);
  margin-top: 0.25rem;
  display: none;
}

.form-group.has-error input,
.form-group.has-error select {
  border-color: var(--accent-red);
}

.form-group.has-error .field-error {
  display: block;
}

.form-checkbox {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  margin: 1.25rem 0;
}

.form-checkbox input[type="checkbox"] {
  width: auto;
  margin-top: 0.25rem;
  accent-color: var(--gold);
}

.form-checkbox label {
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-bottom: 0;
}

.form-checkbox label a {
  color: var(--gold);
}

.order-form .btn-gold {
  width: 100%;
  padding: 1rem;
  font-size: 1.05rem;
  margin-top: 0.5rem;
}

.order-form .form-guarantee {
  text-align: center;
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-top: 0.75rem;
}

.order-form .form-success {
  display: none;
  text-align: center;
  padding: 2rem;
  color: var(--gold);
}

.order-form .form-success h3 {
  margin-bottom: 0.5rem;
}

.order-form .form-success p {
  color: var(--text-muted);
}

/* ========== Product Showcase ========== */
.product-showcase {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 2rem;
  align-items: center;
}

.showcase-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 2rem;
  align-items: center;
}

/* ========== Section: Final CTA ========== */
.section-final-cta {
  position: relative;
  text-align: center;
  padding: 5rem 0;
  overflow: hidden;
}

/* ========== What's Inside (Table of Contents) ========== */
.toc-list {
  list-style: none;
  padding: 0;
}

.toc-list li {
  padding: 0.6rem 0;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 0.75rem;
  color: var(--text);
  font-size: 0.95rem;
}

.toc-list li::before {
  content: attr(data-section);
  font-family: var(--font-display);
  font-size: 1.1rem;
  color: var(--gold);
  min-width: 1.5rem;
}

/* ========== Newsletter Section ========== */
.newsletter-section {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 2rem;
  text-align: center;
  max-width: 520px;
  margin: 0 auto;
}

.newsletter-section h3 { margin-bottom: 0.5rem; }
.newsletter-section p { color: var(--text-muted); margin-bottom: 1rem; font-size: 0.95rem; }

.newsletter-form {
  display: flex;
  gap: 0.5rem;
  max-width: 400px;
  margin: 0 auto;
}

.newsletter-form input {
  flex: 1;
  padding: 0.65rem 0.85rem;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  font-family: var(--font-body);
}

.newsletter-form input:focus {
  outline: none;
  border-color: var(--gold);
}

.newsletter-form .btn { white-space: nowrap; }

/* ========== Pro Badge ========== */
.badge-pro {
  background: var(--accent-purple);
  color: var(--white);
  padding: 0.2rem 0.5rem;
  font-size: 0.7rem;
  border-radius: 3px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}


/* ========== Coming Soon ========== */
.coming-soon {
  background: var(--bg-elevated);
  border: 1px dashed var(--border);
  border-radius: var(--radius-lg);
  padding: 1.5rem 2rem;
  text-align: center;
  color: var(--text-muted);
  font-size: 0.95rem;
}

/* ========== Accordion (FAQ) ========== */
.accordion-item {
  border-bottom: 1px solid var(--border);
}

.accordion-item details {
  padding: 0;
}

.accordion-item summary {
  padding: 1rem 0;
  cursor: pointer;
  font-weight: 600;
  color: var(--white);
  font-size: 1rem;
  list-style: none;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.accordion-item summary::-webkit-details-marker {
  display: none;
}

.accordion-item summary::after {
  content: '+';
  font-size: 1.25rem;
  color: var(--gold);
  transition: transform 0.2s;
}

.accordion-item details[open] summary::after {
  content: '\2212';
}

.accordion-panel {
  padding: 0 0 1rem;
}

.accordion-panel p {
  color: var(--text-muted);
  font-size: 0.95rem;
  line-height: 1.7;
}

/* ========== Legal Pages ========== */
.legal-page {
  padding: 2rem 0 4rem;
}

.legal-page h1 {
  margin-bottom: 0.5rem;
}

.legal-page .updated {
  color: var(--text-muted);
  font-size: 0.9rem;
  margin-bottom: 2rem;
}

.legal-page h2 {
  font-size: 1.3rem;
  margin-top: 2rem;
  margin-bottom: 0.75rem;
  color: var(--gold);
}

.legal-page p,
.legal-page li {
  color: var(--text-muted);
  line-height: 1.7;
  font-size: 0.95rem;
}

.legal-page ul {
  margin-bottom: 1rem;
  padding-left: 1.5rem;
}

.legal-page li {
  list-style: disc;
  margin-bottom: 0.35rem;
}

.legal-page a {
  color: var(--gold);
}

/* ========== Contact Form ========== */
.contact-form {
  max-width: 560px;
  margin: 0 auto;
}

/* ========== Sample Page Tabs ========== */
.tabs {
  display: flex;
  gap: 0;
  border-bottom: 1px solid var(--border);
  margin-bottom: 2rem;
  overflow-x: auto;
}

.tab-btn {
  padding: 0.75rem 1.25rem;
  background: none;
  border: none;
  color: var(--text-muted);
  font-family: var(--font-body);
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  border-bottom: 2px solid transparent;
  transition: all 0.2s;
  white-space: nowrap;
}

.tab-btn:hover {
  color: var(--text);
}

.tab-btn.active {
  color: var(--gold);
  border-bottom-color: var(--gold);
}

.tab-panel {
  display: none;
}

.tab-panel.active {
  display: block;
}

/* ========== Report Header (Sample Pages) ========== */
.report-header {
  text-align: center;
  padding: 3rem 0 2rem;
  border-bottom: 1px solid var(--border);
}

.report-header h1 {
  margin-bottom: 0.5rem;
}

.report-header .chart-badges {
  justify-content: center;
}

.report-subtitle {
  color: var(--text-muted);
  font-size: 1.1rem;
  margin-bottom: 1rem;
}

.report-meta {
  display: flex;
  justify-content: center;
  gap: 1.5rem;
  flex-wrap: wrap;
  color: var(--text-muted);
  font-size: 0.95rem;
  margin-bottom: 1.25rem;
}

/* ========== Report Wheel (Sample Pages) ========== */
.report-wheel {
  text-align: center;
  padding: 2rem 0;
}

.report-wheel img {
  display: block;
  max-width: 520px;
  width: 100%;
  height: auto;
  margin: 0 auto;
  border-radius: var(--radius-lg);
}

/* ========== Report Content (Sample Pages) ========== */
.report-content {
  padding: 2rem 0 4rem;
}

.report-content .container {
  max-width: 780px;
}

.report-content h2 {
  font-family: var(--font-heading);
  font-size: 1.8rem;
  color: var(--gold);
  margin-top: 3rem;
  margin-bottom: 1rem;
  padding-top: 1.5rem;
  border-top: 1px solid var(--border);
}

.report-content h2:first-child {
  margin-top: 0;
  padding-top: 0;
  border-top: none;
}

.report-content h3 {
  font-size: 1.15rem;
  font-weight: 600;
  margin-top: 1.5rem;
  margin-bottom: 0.5rem;
}

.report-content p {
  font-size: 1.1rem;
  line-height: 1.85;
  margin-bottom: 1.15rem;
  color: var(--text);
}

.report-content ul,
.report-content ol {
  padding-left: 1.5rem;
  margin-bottom: 1rem;
}

.report-content li {
  line-height: 1.65;
  margin-bottom: 0.35rem;
  color: var(--text);
}

.report-content blockquote {
  border-left: 3px solid var(--gold);
  padding-left: 1rem;
  margin: 1.5rem 0;
  color: var(--text-muted);
  font-style: italic;
}

/* ========== Report TOC ========== */
.report-toc {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 1.5rem 2rem;
  margin-bottom: 3rem;
}

.report-toc h2 {
  font-size: 1.2rem;
  margin-bottom: 1rem;
  color: var(--gold);
}

.report-toc ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

.report-toc li {
  padding: 0.4rem 0;
  border-bottom: 1px solid var(--border);
}

.report-toc li:last-child {
  border-bottom: none;
}

.report-toc a {
  color: var(--text);
  text-decoration: none;
  transition: color 0.2s;
}

.report-toc a:hover {
  color: var(--gold);
}

/* ========== Report Section ========== */
.report-section {
  margin-bottom: 3rem;
}

.report-section h2 {
  font-size: 1.6rem;
  color: var(--gold);
  margin-bottom: 1.25rem;
  padding-bottom: 0.75rem;
  border-bottom: 2px solid var(--gold);
}

.report-section h3 {
  font-size: 1.15rem;
  color: var(--text);
  margin: 2em 0 0.75em;
  padding-bottom: 0.4rem;
  border-bottom: 1px solid var(--border);
}

.report-section p {
  font-size: 1.1rem;
  margin-bottom: 1.25em;
  line-height: 1.85;
}

/* ========== Report Data Page ========== */
.report-data-page {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 2rem;
  margin-top: 3rem;
}

.report-data-page h2 {
  font-size: 1.4rem;
  color: var(--gold);
  margin-bottom: 1.5rem;
  padding-bottom: 0.75rem;
  border-bottom: 2px solid var(--gold);
}

.report-data-page h3 {
  color: var(--text);
  margin: 1.5em 0 0.75em;
}

.report-data-page h4 {
  color: var(--text-muted);
  margin: 1.25em 0 0.5em;
  font-size: 0.95rem;
}

.report-data-page table {
  width: 100%;
  border-collapse: collapse;
  margin: 0.75rem 0 1.5rem;
  font-size: 0.9rem;
}

.report-data-page th,
.report-data-page td {
  padding: 0.5rem 0.75rem;
  text-align: left;
  border: 1px solid var(--border);
}

.report-data-page th {
  background: var(--gold);
  color: var(--bg-navy);
  font-weight: 600;
}

.report-data-page tr:nth-child(even) {
  background: rgba(255,255,255,0.03);
}

.report-data-page details {
  margin: 1rem 0;
}

.report-data-page summary {
  cursor: pointer;
  padding: 0.5rem;
  background: rgba(255,255,255,0.05);
  border-radius: 4px;
  color: var(--text);
}

.report-data-page summary:hover {
  background: rgba(255,255,255,0.08);
}

.report-data-page pre {
  font-family: "Courier New", Courier, monospace;
  font-size: 0.8em;
  background: rgba(0,0,0,0.2);
  padding: 1rem;
  border: 1px solid var(--border);
  border-radius: 4px;
  overflow-x: auto;
  white-space: pre;
  color: var(--text-muted);
}

/* ========== Sticky CTA Strip (Sample Pages) ========== */
.cta-strip {
  position: sticky;
  bottom: 0;
  z-index: 90;
  background: var(--bg-navy);
  border-top: 1px solid var(--border);
  padding: 1rem 0;
}

.cta-strip .container {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  flex-wrap: wrap;
}

.cta-strip p {
  margin: 0;
  font-weight: 500;
  color: var(--text-muted);
  font-size: 0.95rem;
}

/* ========== Badge Gold ========== */
.badge-gold {
  display: inline-block;
  background: rgba(212, 168, 83, 0.15);
  color: var(--gold);
  padding: 0.25rem 0.75rem;
  border-radius: 3px;
  font-size: 0.8rem;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin-bottom: 1rem;
}

/* ========== Pro Comparison ========== */
.pro-compare {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1.5rem;
  margin: 2rem 0;
}

.pro-compare .tier {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 1.5rem;
}

.pro-compare .tier.highlighted {
  border-color: var(--accent-purple);
}

.pro-compare .tier h4 {
  margin-bottom: 0.75rem;
}

.pro-compare .tier ul {
  padding-left: 1.25rem;
}

.pro-compare .tier li {
  list-style: disc;
  margin-bottom: 0.35rem;
  color: var(--text-muted);
  font-size: 0.9rem;
}

/* ========== Pro Upsell Banner ========== */
.pro-upsell {
  background: var(--bg-elevated);
  border: 1px solid rgba(124, 58, 237, 0.2);
  border-radius: var(--radius-lg);
  padding: 1.5rem 2rem;
  text-align: center;
  margin-top: 2rem;
}

.pro-upsell p {
  color: var(--text-muted);
  font-size: 0.95rem;
}

.pro-upsell .pro-prices {
  margin-top: 0.75rem;
  font-size: 0.9rem;
  color: var(--text);
}

.pro-upsell .pro-prices span {
  margin: 0 0.5rem;
}

/* ========== Cookie Consent ========== */
.cookie-banner {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  background: var(--bg-card);
  border-top: 1px solid var(--border);
  padding: 1rem 1.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1rem;
  z-index: 300;
  box-shadow: 0 -4px 20px rgba(0, 0, 0, 0.3);
}

.cookie-banner p {
  color: var(--text-muted);
  font-size: 0.85rem;
  margin: 0;
}

.cookie-banner .btn {
  padding: 0.45rem 1rem;
  font-size: 0.85rem;
}

.cookie-banner .btn-decline {
  background: transparent;
  color: var(--text-muted);
  border: 1px solid var(--border);
}

.cookie-banner .btn-decline:hover {
  border-color: var(--text-muted);
  color: var(--text);
}

.cookie-banner.hidden {
  display: none;
}

/* ========== 404 Page ========== */
.error-page {
  text-align: center;
  padding: 6rem 0;
}

.error-page h1 {
  font-size: 4rem;
  margin-bottom: 0.5rem;
}

.error-page .error-subline {
  color: var(--text-muted);
  font-size: 1.1rem;
  margin-bottom: 2rem;
}

.error-page .error-actions {
  display: flex;
  gap: 1rem;
  justify-content: center;
}

/* ========== Breadcrumb ========== */
.breadcrumb {
  padding: 0.75rem 0;
  font-size: 0.85rem;
  color: var(--text-muted);
}

.breadcrumb a {
  color: var(--text-muted);
}

.breadcrumb a:hover {
  color: var(--gold);
}

.breadcrumb .separator {
  margin: 0 0.5rem;
  opacity: 0.5;
}

/* ========== Disclaimer (inline on product pages) ========== */
.disclaimer {
  color: var(--text-muted);
  font-size: 0.85rem;
  font-style: italic;
  text-align: center;
  padding: 1rem 0;
}

/* ========== Site Footer ========== */
.site-footer {
  border-top: 1px solid var(--border);
  padding: 3rem 0 2rem;
  margin-top: 2rem;
}

.footer-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 2rem;
  margin-bottom: 2rem;
}

.footer-brand {
  font-family: var(--font-display);
  font-size: 1.4rem;
  color: var(--gold);
  margin-bottom: 0.5rem;
}

.footer-links {
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
}

.footer-links a {
  color: var(--text-muted);
  font-size: 0.85rem;
}

.footer-links a:hover {
  color: var(--gold);
}

.footer-contact {
  font-size: 0.85rem;
  color: var(--text-muted);
}

.footer-contact a {
  color: var(--text-muted);
}

.footer-contact a:hover {
  color: var(--gold);
}

.footer-builder {
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-top: 0.5rem;
}

.footer-builder a {
  color: var(--text-muted);
}

.footer-disclaimer {
  color: var(--text-muted);
  font-size: 0.8rem;
  font-style: italic;
  text-align: center;
  padding-top: 1.5rem;
  border-top: 1px solid var(--border);
  margin-top: 1.5rem;
}

.footer-copy {
  color: var(--text-muted);
  font-size: 0.8rem;
  text-align: center;
  margin-top: 0.5rem;
}

/* ========== Focus States (Accessibility) ========== */
a:focus-visible,
button:focus-visible,
input:focus-visible,
select:focus-visible,
textarea:focus-visible,
details summary:focus-visible {
  outline: 2px solid var(--gold);
  outline-offset: 2px;
}

/* ========== Responsive ========== */
@media (max-width: 1024px) {
  h1 { font-size: 2.5rem; }
  .hero-title { font-size: 2.8rem; }
}

@media (max-width: 768px) {
  /* Nav */
  .nav-links {
    display: none;
    position: absolute;
    top: 100%;
    left: 0;
    right: 0;
    background: var(--bg-navy);
    border-bottom: 1px solid var(--border);
    flex-direction: column;
    padding: 1rem 1.5rem;
    gap: 0;
  }

  .nav-links.open {
    display: flex;
  }

  .nav-links li {
    padding: 0.6rem 0;
    border-bottom: 1px solid var(--border);
  }

  .nav-links li:last-child {
    border-bottom: none;
  }

  .nav-toggle {
    display: block;
  }

  /* Hero */
  h1 { font-size: 2rem; }
  .hero { padding: 3rem 0; min-height: auto; }
  .hero-title { font-size: 2.2rem; }
  .hero-subline { font-size: 1rem; }

  /* Product Showcase */
  .product-showcase,
  .showcase-grid {
    grid-template-columns: 1fr;
  }

  .product-showcase .wheel-image,
  .showcase-grid .wheel-image {
    max-width: 300px;
    margin: 0 auto;
  }

  /* Report Meta */
  .report-meta {
    flex-direction: column;
    gap: 0.25rem;
  }

  /* CTA Strip */
  .cta-strip .container {
    flex-direction: column;
    gap: 0.75rem;
    text-align: center;
  }

  .report-section p {
    text-align: left;
  }

  /* Pro Compare */
  .pro-compare {
    grid-template-columns: 1fr;
  }

  /* Footer */
  .footer-grid {
    grid-template-columns: 1fr;
    gap: 1.5rem;
  }

  .footer-links {
    flex-direction: column;
    gap: 0.5rem;
  }

  /* Trust strip */
  .trust-strip {
    font-size: 0.75rem;
  }

  .trust-strip .separator {
    display: none;
  }

  .trust-strip {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 0.5rem;
  }

  /* Cookie banner */
  .cookie-banner {
    flex-direction: column;
    text-align: center;
    gap: 0.75rem;
  }

  .cookie-banner .btn {
    width: 100%;
  }

  /* Sticky CTA */
  .sticky-cta {
    flex-direction: column;
    gap: 0.5rem;
    padding: 0.75rem 1rem;
  }

  /* Newsletter */
  .newsletter-form {
    flex-direction: column;
  }

  /* Wheel hero */
  .wheel-image-hero {
    display: none;
  }
}

@media (max-width: 480px) {
  .container {
    padding: 0 1rem;
  }

  h1 { font-size: 1.75rem; }
  .hero-title { font-size: 1.8rem; }

  .card-grid {
    grid-template-columns: 1fr;
  }

  .steps {
    grid-template-columns: 1fr;
  }

  .hero-actions {
    flex-direction: column;
  }

  .hero-actions .btn {
    width: 100%;
    text-align: center;
  }
}
